const response = $input.first().json.output ?? $input.first().json.text ?? "";

const cleaned = response
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

try {
  const parsed = JSON.parse(cleaned);
  // Merge prediction with the original metrics for downstream use
  const metrics = $('Compute Sprint Metrics Code').first().json;
  return [{
    json: {
      ...parsed,
      sprint_name: metrics.sprint_name,
      completion_pct: metrics.completion_pct,
      remaining_days: metrics.remaining_days,
      total_points: metrics.total_points,
      done_points: metrics.done_points
    }
  }];
} catch (error) {
  // Non-blocking fallback — no alert on parse failure rather than crash
  return [{
    json: {
      risk_level: "on_track",
      risk_score: 0,
      headline: "Prediction parse failed — no alert sent",
      diagnosis: `Invalid JSON returned by Slip Predictor Agent: ${error.message}`,
      recommendations: [],
      tickets_to_watch: [],
      error: true
    }
  }];
}

// --- Inputs ---
const issues = $input.first().json.issues;
const config = $('Config').first().json;
const sprint = $('Fetch Active Sprint').first().json.values[0];

// --- Sprint timing ---
const sprintStart = new Date(sprint.startDate);
const sprintEnd   = new Date(sprint.endDate);
const now         = new Date();

const totalMs       = Math.max(1, sprintEnd - sprintStart);
const elapsedMs     = Math.min(totalMs, Math.max(0, now - sprintStart));
const remainingMs   = Math.max(0, sprintEnd - now);

const totalDays     = totalMs / 86400000;
const remainingDays = remainingMs / 86400000;
const elapsedDays   = elapsedMs / 86400000;
const timeElapsedPct = (elapsedMs / totalMs) * 100;

// --- Points by status category (universal keys) ---
const spField = config.STORY_POINTS_FIELD;
let totalPoints = 0, donePoints = 0, inProgressPoints = 0, todoPoints = 0;
const blockers = [];

for (const issue of issues) {
  const pts = issue.fields?.[spField] ?? 0;
  const catKey = issue.fields?.status?.statusCategory?.key ?? "new";
  const labels = issue.fields?.labels ?? [];
  totalPoints += pts;

  if (catKey === "done")               donePoints += pts;
  else if (catKey === "indeterminate") inProgressPoints += pts;
  else                                 todoPoints += pts;

  // Flag blocked tickets (label or status name containing "block")
  const statusName = (issue.fields?.status?.name ?? "").toLowerCase();
  if (labels.some(l => l.toLowerCase().includes("block")) || statusName.includes("block")) {
    blockers.push({ key: issue.key, summary: issue.fields?.summary, points: pts });
  }
}

// --- Core slip signals ---
const completionPct      = totalPoints > 0 ? (donePoints / totalPoints) * 100 : 0;
const idealCompletionPct = timeElapsedPct;
const slipMargin         = completionPct - idealCompletionPct; // negative = behind

const remainingPoints       = totalPoints - donePoints;
const requiredPointsPerDay  = remainingDays > 0 ? remainingPoints / remainingDays : remainingPoints;
const actualPointsPerDay    = elapsedDays > 0 ? donePoints / elapsedDays : 0;
const velocityGap           = actualPointsPerDay - requiredPointsPerDay; // negative = too slow

return [{
  json: {
    sprint_name:           sprint.name,
    sprint_goal:           sprint.goal || "(no goal set)",
    total_days:            Math.round(totalDays * 10) / 10,
    remaining_days:        Math.round(remainingDays * 10) / 10,
    time_elapsed_pct:      Math.round(timeElapsedPct),
    total_points:          totalPoints,
    done_points:           donePoints,
    in_progress_points:    inProgressPoints,
    todo_points:           todoPoints,
    completion_pct:        Math.round(completionPct),
    ideal_completion_pct:  Math.round(idealCompletionPct),
    slip_margin:           Math.round(slipMargin),
    remaining_points:      remainingPoints,
    required_points_per_day: Math.round(requiredPointsPerDay * 100) / 100,
    actual_points_per_day:   Math.round(actualPointsPerDay * 100) / 100,
    velocity_gap:          Math.round(velocityGap * 100) / 100,
    blocker_count:         blockers.length,
    blockers:              blockers
  }
}];

